import{_ as n,c as t,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Konto hinzufügen: OAuth und Refresh Token-Dualkanal | Antigravity Tools","description":"Lernen Sie zwei Methoden zum Hinzufügen von Konten zu Antigravity Tools kennen. OAuth-Ein-Klick-Autorisierung oder manueller Refresh-Token-Hinzufügen mit Batch-Import, Fehlerbehandlung und Konto-Pool-Verifizierung.","frontmatter":{"title":"Konto hinzufügen: OAuth und Refresh Token-Dualkanal | Antigravity Tools","sidebarTitle":"Google-Konto hinzufügen","subtitle":"Konto hinzufügen: OAuth/Refresh Token-Dualkanal und Best Practices","description":"Lernen Sie zwei Methoden zum Hinzufügen von Konten zu Antigravity Tools kennen. OAuth-Ein-Klick-Autorisierung oder manueller Refresh-Token-Hinzufügen mit Batch-Import, Fehlerbehandlung und Konto-Pool-Verifizierung.","tags":["Kontoverwaltung","OAuth","refresh_token","Google","Best Practices"],"prerequisite":["start-getting-started"],"duration":15,"order":4},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/start/add-account/index.md","filePath":"de/lbjlaq/Antigravity-Manager/start/add-account/index.md"}'),r={name:"de/lbjlaq/Antigravity-Manager/start/add-account/index.md"};function a(s,e,d,l,u,c){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="konto-hinzufugen-oauth-refresh-token-dualkanal-und-best-practices" tabindex="-1">Konto hinzufügen: OAuth/Refresh Token-Dualkanal und Best Practices <a class="header-anchor" href="#konto-hinzufugen-oauth-refresh-token-dualkanal-und-best-practices" aria-label="Permalink to &quot;Konto hinzufügen: OAuth/Refresh Token-Dualkanal und Best Practices&quot;">​</a></h1><p>In Antigravity Tools bedeutet &quot;Konto hinzufügen&quot;, den <code>refresh_token</code> eines Google-Kontos in den lokalen Konto-Pool zu schreiben, damit nachfolgende Reverse-Proxy-Anfragen rotierend verwendet werden können. Sie können über OAuth-Ein-Klick-Autorisierung gehen oder den <code>refresh_token</code> direkt einfügen, um manuell hinzuzufügen.</p><h2 id="was-sie-nach-diesem-kurs-konnen" tabindex="-1">Was Sie nach diesem Kurs können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs können&quot;">​</a></h2><ul><li>Google-Konten über OAuth oder Refresh Token zum Antigravity Tools-Konto-Pool hinzufügen</li><li>Autorisierungslinks kopieren/manuell öffnen und nach erfolgreichem Callback automatisch abschließen</li><li>Wissen, wie man mit Problemen wie fehlendem <code>refresh_token</code> oder nicht verbundenem <code>localhost</code>-Callback umgeht</li></ul><h2 id="ihr-aktuelles-problem" tabindex="-1">Ihr aktuelles Problem <a class="header-anchor" href="#ihr-aktuelles-problem" aria-label="Permalink to &quot;Ihr aktuelles Problem&quot;">​</a></h2><ul><li>Sie haben auf &quot;OAuth-Autorisierung&quot; geklickt, aber es wird immer geladen, oder der Browser zeigt <code>localhost refused to connect</code> an</li><li>Autorisierung war erfolgreich, aber es wird &quot;Kein Refresh Token erhalten&quot; angezeigt</li><li>Sie haben nur einen <code>refresh_token</code> und wissen nicht, wie Sie ihn gleichzeitig im Batch importieren können</li></ul><h2 id="wann-sie-diese-methode-verwenden" tabindex="-1">Wann Sie diese Methode verwenden <a class="header-anchor" href="#wann-sie-diese-methode-verwenden" aria-label="Permalink to &quot;Wann Sie diese Methode verwenden&quot;">​</a></h2><ul><li>Sie möchten Konten auf die stabilste Weise hinzufügen (priorisieren Sie OAuth)</li><li>Ihnen liegt mehr an Migrations- und Backupfähigkeit (Refresh Token eignet sich besser als &quot;Konto-Pool-Asset&quot;)</li><li>Sie müssen viele Konten hinzufügen und möchten <code>refresh_token</code> im Batch importieren (unterstützt Extraktion aus Text/JSON)</li></ul><h2 id="🎒-vorbereitungen" tabindex="-1">🎒 Vorbereitungen <a class="header-anchor" href="#🎒-vorbereitungen" aria-label="Permalink to &quot;🎒 Vorbereitungen&quot;">​</a></h2><ul><li>Sie haben Antigravity Tools Desktop installiert und können es öffnen</li><li>Sie wissen, wo sich der Einstieg befindet: Linkes Navigationsmenü → <code>Accounts</code>-Seite (Routing siehe <code>source/lbjlaq/Antigravity-Manager/src/App.tsx</code>)</li></ul><div class="info custom-block"><p class="custom-block-title">Zwei Schlüsselbegriffe in dieser Lektion</p><p><strong>OAuth</strong>: Ein Prozess, bei dem &quot;in den Browser zum Anmelden und Autorisieren gesprungen&quot; wird. Antigravity Tools startet lokal eine temporäre Callback-Adresse (<code>http://localhost/127.0.0.1/[::1]:&lt;port&gt;/oauth-callback</code>, automatisch je nach IPv4/IPv6-Listenstatus ausgewählt), wartet darauf, dass der Browser mit einem <code>code</code> zurückkommt, und tauscht ihn dann gegen token. (Implementierung siehe <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs</code>)</p><p><strong>refresh_token</strong>: Ein &quot;langfristig verwendbares Token zum Aktualisieren von access_token&quot;. Bei diesem Projekt wird beim Hinzufügen von Konten zuerst damit ein access_token eingeholt, dann die echte E-Mail-Adresse von Google abgerufen und die im Frontend eingegebene E-Mail ignoriert. (Implementierung siehe <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs</code>)</p></div><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>&quot;Konto hinzufügen&quot; in Antigravity Tools dient letztendlich dazu, einen verfügbaren <code>refresh_token</code> zu erhalten und die Kontoinformationen in den lokalen Konto-Pool zu schreiben.</p><ul><li><strong>OAuth-Kanal</strong>: Die Anwendung generiert den Autorisierungslink für Sie und überwacht den lokalen Callback; nach Abschluss der Autorisierung wird automatisch das Token getauscht und das Konto gespeichert (siehe <code>prepare_oauth_url</code>, <code>start_oauth_login</code>, <code>complete_oauth_login</code>)</li><li><strong>Refresh Token-Kanal</strong>: Sie fügen den <code>refresh_token</code> direkt ein, die Anwendung verwendet ihn zum Aktualisieren des access_token, ruft die echte E-Mail-Adresse von Google ab und speichert sie (siehe <code>add_account</code>)</li></ul><h2 id="machen-sie-mit" tabindex="-1">Machen Sie mit <a class="header-anchor" href="#machen-sie-mit" aria-label="Permalink to &quot;Machen Sie mit&quot;">​</a></h2><h3 id="schritt-1-offnen-sie-das-dialogfeld-konto-hinzufugen" tabindex="-1">Schritt 1: Öffnen Sie das Dialogfeld &quot;Konto hinzufügen&quot; <a class="header-anchor" href="#schritt-1-offnen-sie-das-dialogfeld-konto-hinzufugen" aria-label="Permalink to &quot;Schritt 1: Öffnen Sie das Dialogfeld &quot;Konto hinzufügen&quot;&quot;">​</a></h3><p><strong>Warum</strong> Alle Hinzufügungs-Einstiegspunkte sind auf der <code>Accounts</code>-Seite zentralisiert.</p><p>Vorgehensweise: Gehen Sie zur <code>Accounts</code>-Seite und klicken Sie auf die Schaltfläche <strong>Add Account</strong> rechts (Komponente: <code>AddAccountDialog</code>).</p><p><strong>Was Sie sehen sollten</strong>: Ein Dialogfeld mit 3 Registerkarten öffnet sich: <code>OAuth</code> / <code>Refresh Token</code> / <code>Import</code> (siehe <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx</code>).</p><h3 id="schritt-2-bevorzugen-sie-oauth-ein-klick-autorisierung-empfohlen" tabindex="-1">Schritt 2: Bevorzugen Sie OAuth-Ein-Klick-Autorisierung (empfohlen) <a class="header-anchor" href="#schritt-2-bevorzugen-sie-oauth-ein-klick-autorisierung-empfohlen" aria-label="Permalink to &quot;Schritt 2: Bevorzugen Sie OAuth-Ein-Klick-Autorisierung (empfohlen)&quot;">​</a></h3><p><strong>Warum</strong> Dies ist der vom Produkt standardmäßig empfohlene Pfad: Die Anwendung generiert selbst den Autorisierungslink, öffnet automatisch den Browser und speichert automatisch nach dem Callback.</p><ol><li>Wechseln Sie zur Registerkarte <code>OAuth</code>.</li><li>Kopieren Sie zunächst den Autorisierungslink: Nach dem Öffnen des Dialogfelds wird automatisch <code>prepare_oauth_url</code> aufgerufen, um die URL vorzuzugenerieren (Frontend-Aufruf siehe <code>AddAccountDialog.tsx:111-125</code>; Backend-Generierung und -Überwachung siehe <code>oauth_server.rs</code>).</li><li>Klicken Sie auf <strong>Start OAuth</strong> (entspricht Frontend <code>startOAuthLogin()</code> / Backend <code>start_oauth_login</code>), damit die Anwendung den Standardbrowser öffnet und auf den Callback wartet.</li></ol><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Ein kopierbarer Autorisierungslink erscheint im Dialogfeld (Ereignisname: <code>oauth-url-generated</code>)</li><li>Der Browser öffnet die Google-Autorisierungsseite; nach der Autorisierung wird er zu einer lokalen Adresse weitergeleitet und zeigt &quot;Authorization Successful!&quot; an (<code>oauth_success_html()</code>)</li></ul><h3 id="schritt-3-wenn-oauth-nicht-automatisch-abgeschlossen-wird-verwenden-sie-oauth-abschließen-zum-manuellen-abschluss" tabindex="-1">Schritt 3: Wenn OAuth nicht automatisch abgeschlossen wird, verwenden Sie &quot;OAuth abschließen&quot; zum manuellen Abschluss <a class="header-anchor" href="#schritt-3-wenn-oauth-nicht-automatisch-abgeschlossen-wird-verwenden-sie-oauth-abschließen-zum-manuellen-abschluss" aria-label="Permalink to &quot;Schritt 3: Wenn OAuth nicht automatisch abgeschlossen wird, verwenden Sie &quot;OAuth abschließen&quot; zum manuellen Abschluss&quot;">​</a></h3><p><strong>Warum</strong> Der OAuth-Prozess besteht aus zwei Phasen: Browser-Autorisierung erhält <code>code</code>, dann tauscht die Anwendung den <code>code</code> gegen token. Selbst wenn Sie nicht auf &quot;Start OAuth&quot; geklickt haben, solange Sie den Autorisierungslink manuell geöffnet und den Callback abgeschlossen haben, wird das Dialogfeld versuchen, automatisch abzuschließen; wenn dies nicht gelingt, können Sie einmal manuell klicken.</p><ol><li>Wenn Sie &quot;den Link in Ihren eigenen Browser kopiert und geöffnet&quot; haben (statt den Standardbrowser), empfängt die Anwendung nach dem Autorisierungs-Callback das Ereignis <code>oauth-callback-received</code> und ruft automatisch <code>completeOAuthLogin()</code> auf (siehe <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx:67-109</code>).</li><li>Wenn Sie den automatischen Abschluss nicht sehen, klicken Sie auf <strong>Finish OAuth</strong> im Dialogfeld (entspricht Backend <code>complete_oauth_login</code>).</li></ol><p><strong>Was Sie sehen sollten</strong>: Das Dialogfeld zeigt Erfolg an und schließt automatisch; ein neues Konto erscheint in der <code>Accounts</code>-Liste.</p><div class="tip custom-block"><p class="custom-block-title">Tipp: Bei Callback-Verbindungsproblemen zuerst Link kopieren</p><p>Das Backend versucht, gleichzeitig IPv6 <code>::1</code> und IPv4 <code>127.0.0.1</code> zu überwachen und wählt je nach Überwachungsstatus <code>localhost/127.0.0.1/[::1]</code> als Callback-Adresse, hauptsächlich um Verbindungsfehler zu vermeiden, die entstehen, wenn &quot;Browser localhost zu IPv6 auflöst&quot;. (siehe <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>)</p></div><h3 id="schritt-4-konto-manuell-mit-refresh-token-hinzufugen-unterstutzt-batch" tabindex="-1">Schritt 4: Konto manuell mit Refresh Token hinzufügen (unterstützt Batch) <a class="header-anchor" href="#schritt-4-konto-manuell-mit-refresh-token-hinzufugen-unterstutzt-batch" aria-label="Permalink to &quot;Schritt 4: Konto manuell mit Refresh Token hinzufügen (unterstützt Batch)&quot;">​</a></h3><p><strong>Warum</strong> Wenn Sie keinen <code>refresh_token</code> erhalten können (oder Sie bevorzugen &quot;migrierbare Assets&quot;), ist das direkte Hinzufügen mit Refresh Token kontrollierbarer.</p><ol><li>Wechseln Sie zur Registerkarte <code>Refresh Token</code>.</li><li>Fügen Sie den <code>refresh_token</code> in das Textfeld ein.</li></ol><p>Unterstützte Eingabeformate (Frontend analysiert und fügt im Batch hinzu):</p><table tabindex="0"><thead><tr><th>Eingabetyp</th><th>Beispiel</th><th>Analyse-Logik</th></tr></thead><tbody><tr><td>Reiner Token-Text</td><td><code>1//abc...</code></td><td>Regex-Extraktion: <code>/1\\/\\/[a-zA-Z0-9_\\-]+/g</code> (siehe <code>AddAccountDialog.tsx:213-220</code>)</td></tr><tr><td>Eingebettet in langen Text</td><td>Logs/Exporttext enthalten mehrere <code>1//...</code></td><td>Regex-Batch-Extraktion mit Deduplizierung (siehe <code>AddAccountDialog.tsx:213-224</code>)</td></tr><tr><td>JSON-Array</td><td><code>[{&quot;refresh_token&quot;:&quot;1//...&quot;}]</code></td><td>Array-Parser und <code>item.refresh_token</code> extrahieren (siehe <code>AddAccountDialog.tsx:198-207</code>)</td></tr></tbody></table><p>Nach dem Klicken auf <strong>Confirm</strong> ruft das Dialogfeld nacheinander <code>onAdd(&quot;&quot;, token)</code> pro Token auf (siehe <code>AddAccountDialog.tsx:231-248</code>), landet schließlich im Backend <code>add_account</code>.</p><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Das Dialogfeld zeigt den Batch-Fortschritt (z. B. <code>1/5</code>)</li><li>Nach dem Erfolg erscheinen neue Konten in der <code>Accounts</code>-Liste</li></ul><h3 id="schritt-5-bestatigen-sie-konto-pool-ist-verfugbar" tabindex="-1">Schritt 5: Bestätigen Sie &quot;Konto-Pool ist verfügbar&quot; <a class="header-anchor" href="#schritt-5-bestatigen-sie-konto-pool-ist-verfugbar" aria-label="Permalink to &quot;Schritt 5: Bestätigen Sie &quot;Konto-Pool ist verfügbar&quot;&quot;">​</a></h3><p><strong>Warum</strong> Erfolgreiches Hinzufügen bedeutet nicht &quot;sofort stabil nutzbar&quot;. Das Backend löst nach dem Hinzufügen automatisch ein &quot;Refresh-Quota&quot; aus und versucht während des Proxy-Betriebs, den Token-Pool neu zu laden, damit die Änderung sofort wirksam wird.</p><p>Sie können es mit den folgenden 2 Signalen bestätigen:</p><ol><li>Das Konto erscheint in der Liste und zeigt die E-Mail-Adresse (die E-Mail stammt vom Backend <code>get_user_info</code>, nicht von Ihrer eingegebenen E-Mail).</li><li>Die Kontingent-/Abonnement-Informationen des Kontos beginnen mit der Aktualisierung (das Backend ruft automatisch <code>internal_refresh_account_quota</code> auf).</li></ol><p><strong>Was Sie sehen sollten</strong>: Nach dem Hinzufügen müssen Sie nicht manuell aktualisieren, das Konto beginnt mit dem Anzeigen von Kontingentinformationen (Erfolg ist am tatsächlichen Interface-Display zu erkennen).</p><h2 id="kontrollpunkte-✅" tabindex="-1">Kontrollpunkte ✅ <a class="header-anchor" href="#kontrollpunkte-✅" aria-label="Permalink to &quot;Kontrollpunkte ✅&quot;">​</a></h2><ul><li>Die E-Mail-Adresse des neu hinzugefügten Kontos ist in der Kontenliste sichtbar</li><li>Es verbleibt kein &quot;loading&quot;-Status länger als akzeptabel (OAuth-Callback-Completing sollte schnell sein)</li><li>Wenn Sie Proxy ausführen, können neue Konten schnell an der Planung teilnehmen (das Backend versucht, neu zu laden)</li></ul><h2 id="warnungen-vor-stolpersteinen" tabindex="-1">Warnungen vor Stolpersteinen <a class="header-anchor" href="#warnungen-vor-stolpersteinen" aria-label="Permalink to &quot;Warnungen vor Stolpersteinen&quot;">​</a></h2><h3 id="_1-oauth-zeigt-kein-refresh-token-erhalten" tabindex="-1">1) OAuth zeigt &quot;Kein Refresh Token erhalten&quot; <a class="header-anchor" href="#_1-oauth-zeigt-kein-refresh-token-erhalten" aria-label="Permalink to &quot;1) OAuth zeigt &quot;Kein Refresh Token erhalten&quot;&quot;">​</a></h3><p>Das Backend prüft explizit in <code>start_oauth_login/complete_oauth_login</code>, ob <code>refresh_token</code> vorhanden ist; wenn nicht, wird eine Fehlermeldung mit Lösung zurückgegeben (siehe <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs:45-56</code>).</p><p>Behandlung laut Quellcode-Hinweis:</p><ol><li>Öffnen Sie <code>https://myaccount.google.com/permissions</code></li><li>Widerrufen Sie die Zugriffsberechtigung von <strong>Antigravity Tools</strong></li><li>Kehren Sie zur Anwendung zurück und durchlaufen Sie OAuth erneut</li></ol><blockquote><p>Sie können auch direkt zum Refresh-Token-Kanal dieser Lektion wechseln.</p></blockquote><h3 id="_2-browser-zeigt-localhost-refused-to-connect-an" tabindex="-1">2) Browser zeigt <code>localhost refused to connect</code> an <a class="header-anchor" href="#_2-browser-zeigt-localhost-refused-to-connect-an" aria-label="Permalink to &quot;2) Browser zeigt `localhost refused to connect` an&quot;">​</a></h3><p>OAuth-Callback erfordert, dass der Browser die lokale Callback-Adresse anfordert. Um die Ausfallrate zu senken, wird das Backend:</p><ul><li>Versuchen, gleichzeitig <code>127.0.0.1</code> und <code>::1</code> zu überwachen</li><li><code>localhost</code> nur verwenden, wenn beide verfügbar sind, andernfalls zwingend <code>127.0.0.1</code> oder <code>[::1]</code></li></ul><p>Entsprechende Implementierung siehe <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>.</p><h3 id="_3-wechseln-zu-anderen-registerkarten-bricht-oauth-vorbereitung-ab" tabindex="-1">3) Wechseln zu anderen Registerkarten bricht OAuth-Vorbereitung ab <a class="header-anchor" href="#_3-wechseln-zu-anderen-registerkarten-bricht-oauth-vorbereitung-ab" aria-label="Permalink to &quot;3) Wechseln zu anderen Registerkarten bricht OAuth-Vorbereitung ab&quot;">​</a></h3><p>Wenn das Dialogfeld von <code>OAuth</code> zu einer anderen Registerkarte wechselt, ruft das Frontend <code>cancelOAuthLogin()</code> auf und leert die URL (siehe <code>AddAccountDialog.tsx:127-136</code>).</p><p>Wenn Sie gerade autorisieren, wechseln Sie nicht eilig die Registerkarte.</p><h3 id="_4-korrekte-falsche-beispiele-fur-refresh-token" tabindex="-1">4) Korrekte/Falsche Beispiele für Refresh Token <a class="header-anchor" href="#_4-korrekte-falsche-beispiele-fur-refresh-token" aria-label="Permalink to &quot;4) Korrekte/Falsche Beispiele für Refresh Token&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Beispiel</th><th>Wird erkannt</th><th>Grund</th></tr></thead><tbody><tr><td><code>1//0gAbC...</code></td><td>✓</td><td>Entspricht <code>1//</code>-Prefix-Regel (siehe <code>AddAccountDialog.tsx:215-219</code>)</td></tr><tr><td><code>ya29.a0...</code></td><td>✗</td><td>Entspricht nicht der Frontend-Extraktionsregel, wird als ungültige Eingabe behandelt</td></tr></tbody></table><h2 id="zusammenfassung-der-lektion" tabindex="-1">Zusammenfassung der Lektion <a class="header-anchor" href="#zusammenfassung-der-lektion" aria-label="Permalink to &quot;Zusammenfassung der Lektion&quot;">​</a></h2><ul><li>OAuth: Geeignet für &quot;schnell&quot;, unterstützt auch Kopieren des Links zu Ihrem bevorzugten Browser und automatischen/manuellen Abschluss</li><li>Refresh Token: Geeignet für &quot;stabil&quot; und &quot;migrierbar&quot;, unterstützt Batch-Extraktion von <code>1//...</code> aus Text/JSON</li><li>Wenn Sie keinen <code>refresh_token</code> erhalten können, widerrufen Sie die Berechtigung laut Fehlerhinweis und wiederholen Sie, oder wechseln Sie direkt zum Refresh-Token-Kanal</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><p>In der nächsten Lektion machen wir etwas Solideres: den Konto-Pool zu einem &quot;migrierbaren Asset&quot; zu machen.</p><blockquote><p>Gehen Sie zu <strong><a href="./../backup-migrate/">Konto-Backup und Migration: Import/Export, V1/DB-Hot-Migration</a></strong>.</p></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie zum Ausklappen, um Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Wichtige Ereignisnamen</strong>:</p><ul><li><code>oauth-url-generated</code>: Backend sendet OAuth-URL an Frontend nach Generierung (siehe <code>oauth_server.rs:250-252</code>)</li><li><code>oauth-callback-received</code>: Backend benachrichtigt Frontend nach Empfang von Callback und Analyse von code (siehe <code>oauth_server.rs:177-180</code> / <code>oauth_server.rs:232-235</code>)</li></ul><p><strong>Wichtige Commands</strong>:</p><ul><li><code>prepare_oauth_url</code>: Vor-Generieren von Autorisierungslink und Start der Callback-Überwachung (siehe <code>src-tauri/src/commands/mod.rs:469-473</code>)</li><li><code>start_oauth_login</code>: Standardbrowser öffnen und auf Callback warten (siehe <code>src-tauri/src/commands/mod.rs:339-401</code>)</li><li><code>complete_oauth_login</code>: Browser nicht öffnen, nur auf Callback warten und Token-Austausch abschließen (siehe <code>src-tauri/src/commands/mod.rs:405-467</code>)</li><li><code>add_account</code>: Konto mit refresh_token speichern (siehe <code>src-tauri/src/commands/mod.rs:19-60</code>)</li></ul></details>',67)])])}const k=n(r,[["render",a]]);export{g as __pageData,k as default};
